// ============================================
// GENERADOR DE UPLINKS LORAWAN PARA CHIRPSTACK
// Formato: [Temp_H][Temp_L][Hum][Pres_H][Pres_L][Bat]
// 6 bytes totales
// ============================================

function bytesToHex(bytes) {
    return bytes.map(b => b.toString(16).padStart(2, '0')).join('').toUpperCase();
}

function generarDatosSensor() {
    // Temperatura: 20 a 35°C (2 bytes, signed, x100)
    const temperatura = 20 + Math.random() * 15;
    const tempInt = Math.round(temperatura * 100);
    const tempBytes = [
        (tempInt >> 8) & 0xFF,
        tempInt & 0xFF
    ];

    // Humedad: 40-70% (1 byte)
    const humedad = Math.round(40 + Math.random() * 30);

    // Presión: 950-1000 hPa (2 bytes)
    const presion = Math.round(950 + Math.random() * 50);
    const presionBytes = [
        (presion >> 8) & 0xFF,
        presion & 0xFF
    ];

    // Voltaje batería: 3.5-4.0V (1 byte, x100, offset 200)
    const voltaje = 3.5 + Math.random() * 0.5;
    const voltajeByte = Math.round((voltaje * 100) - 200);

    return {
        bytes: [...tempBytes, humedad, ...presionBytes, voltajeByte],
        valores: {
            temperatura: temperatura.toFixed(2),
            humedad: humedad,
            presion: presion,
            voltaje: voltaje.toFixed(2)
        }
    };
}

const sensorData = generarDatosSensor();
const payloadHex = bytesToHex(sensorData.bytes);
const timestamp = new Date().toISOString();

const devEUI = "70B3D57ED005ABCD";
const gatewayID = "2C7F71115310007";
const fPort = 1;
const fCnt = flow.get('frameCounter') || 1;
flow.set('frameCounter', fCnt + 1);

// Estructura compatible con ChirpStack Gateway Bridge
// Formato Semtech UDP simulado
const phyPayload = Buffer.from(payloadHex, 'hex').toString('base64');

msg.payload = {
    devEUI: devEUI,
    gatewayID: gatewayID,
    fPort: fPort,
    fCnt: fCnt,
    phyPayload: phyPayload,
    payloadHex: payloadHex,
    valoresReales: sensorData.valores,
    rxInfo: {
        rssi: -45 - Math.round(Math.random() * 40),
        snr: 5 + Math.random() * 5,
        frequency: 915200000,
        dr: 3,
        timestamp: Math.floor(Date.now() / 1000)
    },
    timestamp: timestamp
};

node.warn(`📡 Uplink #${fCnt}: ${payloadHex} (${sensorData.bytes.length} bytes)`);
node.warn(`📊 T=${sensorData.valores.temperatura}°C, H=${sensorData.valores.humedad}%, P=${sensorData.valores.presion}hPa, V=${sensorData.valores.voltaje}V`);

return msg;

// ============================================
// EXTRACTOR DE DATOS DECODIFICADOS POR CHIRPSTACK
// ChirpStack ya ejecutó el Codec JavaScript
// Solo extraemos los datos relevantes
// ============================================

try {
    const uplink = msg.payload;

    // ChirpStack publica la estructura decodificada
    // El campo 'data' contiene los valores decodificados por el Codec

    const data = uplink.data || {};
    const deviceInfo = uplink.deviceInfo || {};
    const rxInfo = uplink.rxInfo || {};

    msg.payload = {
        // Información del dispositivo
        devEUI: uplink.devEUI || "N/A",
        deviceName: deviceInfo.deviceName || "N/A",
        applicationID: uplink.applicationID || "N/A",

        // Datos DECODIFICADOS por ChirpStack
        data: {
            temperatura: data.temperatura || null,
            humedad: data.humedad || null,
            presion: data.presion || null,
            voltaje: data.voltaje || null,
            alerta: data.alerta || "N/A"
        },

        // Metadatos
        metadata: {
            fPort: uplink.fPort,
            fCnt: uplink.fCnt,
            confirmed: uplink.confirmed || false,
            rssi: rxInfo.rssi || null,
            snr: rxInfo.snr || null,
            frequency: rxInfo.frequency || null
        },

        // Estado
        estatus: "exito",
        timestamp: new Date().toISOString(),

        // Mensaje informativo
        mensaje: `${uplink.devEUI}: T=${data.temperatura}°C, H=${data.humedad}%, P=${data.presion}hPa, V=${data.voltaje}V - ${data.alerta}`
    };

    node.warn(`✅ Datos decodificados por ChirpStack: T=${data.temperatura}°C`);

    return msg;

} catch (error) {
    node.error(`❌ Error al extraer datos: ${error.message}`);

    msg.payload = {
        estatus: "error",
        timestamp: new Date().toISOString(),
        errores: [error.message],
        mensaje: "Error al procesar uplink decodificado"
    };

    return msg;
}

// Cambiar color del nodo según el estado
const estatus = msg.payload.estatus;

if (estatus === "exito") {
    node.status({
        fill: "green",
        shape: "dot",
        text: `✅ EXITO - ${msg.payload.data.temperatura}°C`
    });
} else {
    node.status({
        fill: "red",
        shape: "dot",
        text: `❌ ERROR`
    });
}

return msg;
